example:
fetch('https://bigstone-api.justparrot.workers.dev/projects', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer YOUR_TOKEN' },
  body: JSON.stringify({ name: 'My Project', desc: 'Project description' })
})
.then(res => res.json())
.then(data => console.log(data))
.catch(err => console.error(err));

fetch('https://bigstone-api.justparrot.workers.dev/auth/register', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ username: 'user1', password: 'securepassword', consent: true })
})
.then(res => res.text())
.then(data => console.log(data));

fetch('https://bigstone-api.justparrot.workers.dev/auth/login', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ username: 'user1', password: 'securepassword' })
})
.then(res => res.json())
.then(data => console.log(data.token));

fetch('https://bigstone-api.justparrot.workers.dev/components', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer YOUR_TOKEN' },
  body: JSON.stringify({ project_id: '123', name: 'Resistor', desc: '220 Ohm' })
})
